import{_ as n,o as s,c as p,ae as e}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"7.1 多 Agent 概述","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/19_Agent管理专题/28.1_multi_agent_overview.md","filePath":"chapters/19_Agent管理专题/28.1_multi_agent_overview.md"}'),l={name:"chapters/19_Agent管理专题/28.1_multi_agent_overview.md"};function t(i,a,c,o,r,d){return s(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="_7-1-多-agent-概述" tabindex="-1">7.1 多 Agent 概述 <a class="header-anchor" href="#_7-1-多-agent-概述" aria-label="Permalink to &quot;7.1 多 Agent 概述&quot;">​</a></h1><h2 id="本节目标" tabindex="-1">本节目标 <a class="header-anchor" href="#本节目标" aria-label="Permalink to &quot;本节目标&quot;">​</a></h2><ul><li>理解多 Agent 协作的原理</li><li>掌握多 Agent 系统架构</li><li>了解适用场景</li></ul><hr><h2 id="_7-1-1-什么是多-agent" tabindex="-1">7.1.1 什么是多 Agent <a class="header-anchor" href="#_7-1-1-什么是多-agent" aria-label="Permalink to &quot;7.1.1 什么是多 Agent&quot;">​</a></h2><h3 id="单-agent-vs-多-agent" tabindex="-1">单 Agent vs 多 Agent <a class="header-anchor" href="#单-agent-vs-多-agent" aria-label="Permalink to &quot;单 Agent vs 多 Agent&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│         单 Agent vs 多 Agent                 │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  单 Agent                                    │</span></span>
<span class="line"><span>│  ├── 一个 Agent 处理所有任务                  │</span></span>
<span class="line"><span>│  ├── 简单高效                               │</span></span>
<span class="line"><span>│  └── 适合单一职责任务                        │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  多 Agent                                    │</span></span>
<span class="line"><span>│  ├── 多个专业 Agent 协作                     │</span></span>
<span class="line"><span>│  ├── 分工明确                               │</span></span>
<span class="line"><span>│  └── 适合复杂任务                           │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><p>![Agent模式]/assets/diagrams/102_agent_modes.png)</p><p>![多Agent架构]/assets/diagrams/03_multi_agent_architecture.png)</p><h3 id="多-agent-优势" tabindex="-1">多 Agent 优势 <a class="header-anchor" href="#多-agent-优势" aria-label="Permalink to &quot;多 Agent 优势&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>优势：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 专业分工</span></span>
<span class="line"><span>   ├── 每个 Agent 专注领域</span></span>
<span class="line"><span>   └── 深度优化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 可扩展性</span></span>
<span class="line"><span>   ├── 轻松添加新 Agent</span></span>
<span class="line"><span>   └── 灵活扩展</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 容错性</span></span>
<span class="line"><span>   ├── 单点故障不影响全局</span></span>
<span class="line"><span>   └── 可替换 Agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 成本优化</span></span>
<span class="line"><span>   ├── 按需调用不同模型</span></span>
<span class="line"><span>   └── 复杂任务分配给强模型</span></span></code></pre></div><hr><h2 id="_7-1-2-系统架构" tabindex="-1">7.1.2 系统架构 <a class="header-anchor" href="#_7-1-2-系统架构" aria-label="Permalink to &quot;7.1.2 系统架构&quot;">​</a></h2><h3 id="架构图" tabindex="-1">架构图 <a class="header-anchor" href="#架构图" aria-label="Permalink to &quot;架构图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│           多 Agent 系统架构                   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│              用户请求                         │</span></span>
<span class="line"><span>│                 │                            │</span></span>
<span class="line"><span>│                 ▼                            │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │         Agent Dispatcher              │  │</span></span>
<span class="line"><span>│  │         任务分发器                     │  │</span></span>
<span class="line"><span>│  └───────────────────┬───────────────────┘  │</span></span>
<span class="line"><span>│                      │                       │</span></span>
<span class="line"><span>│          ┌──────────┼──────────┐            │</span></span>
<span class="line"><span>│          ▼          ▼          ▼            │</span></span>
<span class="line"><span>│     ┌────────┐ ┌────────┐ ┌────────┐       │</span></span>
<span class="line"><span>│     │Agent A │ │Agent B │ │Agent C │       │</span></span>
<span class="line"><span>│     │  (UI)  │ │(Logic) │ │(Data)  │       │</span></span>
<span class="line"><span>│     └────┬───┘ └────┬───┘ └────┬───┘       │</span></span>
<span class="line"><span>│          │          │          │            │</span></span>
<span class="line"><span>│          └──────────┼──────────┘            │</span></span>
<span class="line"><span>│                     │                       │</span></span>
<span class="line"><span>│                     ▼                       │</span></span>
<span class="line"><span>│  ┌───────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │         Result Aggregator             │  │</span></span>
<span class="line"><span>│  │         结果聚合器                     │  │</span></span>
<span class="line"><span>│  └───────────────────┬───────────────────┘  │</span></span>
<span class="line"><span>│                      │                       │</span></span>
<span class="line"><span>│                      ▼                       │</span></span>
<span class="line"><span>│               返回结果                        │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="组件说明" tabindex="-1">组件说明 <a class="header-anchor" href="#组件说明" aria-label="Permalink to &quot;组件说明&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>核心组件：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Dispatcher - 任务分发</span></span>
<span class="line"><span>   → 分析任务</span></span>
<span class="line"><span>   → 选择 Agent</span></span>
<span class="line"><span>   → 分配任务</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Agent - 执行单元</span></span>
<span class="line"><span>   → 专业能力</span></span>
<span class="line"><span>   → 独立运行</span></span>
<span class="line"><span>   → 返回结果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Aggregator - 结果聚合</span></span>
<span class="line"><span>   → 合并结果</span></span>
<span class="line"><span>   → 格式统一</span></span>
<span class="line"><span>   → 返回用户</span></span></code></pre></div><hr><h2 id="_7-1-3-agent-类型" tabindex="-1">7.1.3 Agent 类型 <a class="header-anchor" href="#_7-1-3-agent-类型" aria-label="Permalink to &quot;7.1.3 Agent 类型&quot;">​</a></h2><h3 id="按角色分类" tabindex="-1">按角色分类 <a class="header-anchor" href="#按角色分类" aria-label="Permalink to &quot;按角色分类&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agent 角色类型：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 协调者 (Coordinator)</span></span>
<span class="line"><span>   ├── 任务分解</span></span>
<span class="line"><span>   ├── 流程控制</span></span>
<span class="line"><span>   └── 结果汇总</span></span>
<span class="line"><span>   例子：项目经理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 执行者 (Executor)</span></span>
<span class="line"><span>   ├── 具体执行</span></span>
<span class="line"><span>   ├── 工具调用</span></span>
<span class="line"><span>   └── 产出结果</span></span>
<span class="line"><span>   例子：开发人员</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 审查者 (Reviewer)</span></span>
<span class="line"><span>   ├── 质量检查</span></span>
<span class="line"><span>   ├── 问题发现</span></span>
<span class="line"><span>   └── 改进建议</span></span>
<span class="line"><span>   例子：代码审查员</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 规划者 (Planner)</span></span>
<span class="line"><span>   ├── 方案设计</span></span>
<span class="line"><span>   ├── 路径规划</span></span>
<span class="line"><span>   └── 策略制定</span></span>
<span class="line"><span>   例子：架构师</span></span></code></pre></div><h3 id="按模型分类" tabindex="-1">按模型分类 <a class="header-anchor" href="#按模型分类" aria-label="Permalink to &quot;按模型分类&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型类型：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 强模型 Agent</span></span>
<span class="line"><span>   ├── GPT-4o / Claude 3.5</span></span>
<span class="line"><span>   ├── 复杂推理</span></span>
<span class="line"><span>   └── 重要决策</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 平衡模型 Agent</span></span>
<span class="line"><span>   ├── GPT-4o-mini / Claude 3 Haiku</span></span>
<span class="line"><span>   ├── 日常任务</span></span>
<span class="line"><span>   └── 成本优化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 轻量模型 Agent</span></span>
<span class="line"><span>   ├── DeepSeek / GLM-4</span></span>
<span class="line"><span>   ├── 简单执行</span></span>
<span class="line"><span>   └── 批量处理</span></span></code></pre></div><hr><h2 id="_7-1-4-协作模式" tabindex="-1">7.1.4 协作模式 <a class="header-anchor" href="#_7-1-4-协作模式" aria-label="Permalink to &quot;7.1.4 协作模式&quot;">​</a></h2><h3 id="模式分类" tabindex="-1">模式分类 <a class="header-anchor" href="#模式分类" aria-label="Permalink to &quot;模式分类&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>协作模式：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 串行模式</span></span>
<span class="line"><span>   A → B → C</span></span>
<span class="line"><span>   └── 顺序执行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 并行模式</span></span>
<span class="line"><span>   A → ┬ → D</span></span>
<span class="line"><span>   B ──┤</span></span>
<span class="line"><span>   C ──┘</span></span>
<span class="line"><span>   └── 同时执行，结果合并</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 分支模式</span></span>
<span class="line"><span>   A → B (条件1)</span></span>
<span class="line"><span>   A → C (条件2)</span></span>
<span class="line"><span>   └── 根据条件选择</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 循环模式</span></span>
<span class="line"><span>   A → B → A → B</span></span>
<span class="line"><span>   └── 迭代优化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 层级模式</span></span>
<span class="line"><span>   A → B → C</span></span>
<span class="line"><span>   └── 逐级传递</span></span></code></pre></div><hr><h2 id="_7-1-5-适用场景" tabindex="-1">7.1.5 适用场景 <a class="header-anchor" href="#_7-1-5-适用场景" aria-label="Permalink to &quot;7.1.5 适用场景&quot;">​</a></h2><h3 id="场景示例" tabindex="-1">场景示例 <a class="header-anchor" href="#场景示例" aria-label="Permalink to &quot;场景示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>适合多 Agent：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 复杂项目开发</span></span>
<span class="line"><span>   ├── 需求分析 Agent</span></span>
<span class="line"><span>   ├── 开发 Agent</span></span>
<span class="line"><span>   ├── 测试 Agent</span></span>
<span class="line"><span>   └── 部署 Agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 全方位客户服务</span></span>
<span class="line"><span>   ├── 接待 Agent</span></span>
<span class="line"><span>   ├── 问题分类 Agent</span></span>
<span class="line"><span>   ├── 处理 Agent</span></span>
<span class="line"><span>   └── 满意度回访</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 内容创作</span></span>
<span class="line"><span>   ├── 选题 Agent</span></span>
<span class="line"><span>   ├── 写作 Agent</span></span>
<span class="line"><span>   ├── 配图 Agent</span></span>
<span class="line"><span>   └── 审核 Agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 数据分析</span></span>
<span class="line"><span>   ├── 采集 Agent</span></span>
<span class="line"><span>   ├── 清洗 Agent</span></span>
<span class="line"><span>   ├── 分析 Agent</span></span>
<span class="line"><span>   └── 可视化 Agent</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不适合多 Agent：</span></span>
<span class="line"><span>- 简单问答</span></span>
<span class="line"><span>- 单一任务</span></span>
<span class="line"><span>- 实时性要求极高</span></span></code></pre></div><hr><h2 id="_7-1-6-subagent-生命周期管理" tabindex="-1">7.1.6 Subagent 生命周期管理 <a class="header-anchor" href="#_7-1-6-subagent-生命周期管理" aria-label="Permalink to &quot;7.1.6 Subagent 生命周期管理&quot;">​</a></h2><h3 id="subagent-的启动与终止" tabindex="-1">Subagent 的启动与终止 <a class="header-anchor" href="#subagent-的启动与终止" aria-label="Permalink to &quot;Subagent 的启动与终止&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Subagent 生命周期                               │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  启动方式                                                         │</span></span>
<span class="line"><span>│  ├── sessions_spawn（主控发起）                                   │</span></span>
<span class="line"><span>│  └── sessions_spawn runtime=&quot;subagent&quot;（后台独立运行）             │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  状态查看                                                         │</span></span>
<span class="line"><span>│  └── /subagents list                                             │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  强制终止                                                         │</span></span>
<span class="line"><span>│  └── /subagents kill &lt;subagent-id&gt;                               │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>│  发送指令                                                         │</span></span>
<span class="line"><span>│  └── /subagents steer &lt;subagent-id&gt; &lt;message&gt;                    │</span></span>
<span class="line"><span>│                                                                  │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="session-target-选择" tabindex="-1">Session Target 选择 <a class="header-anchor" href="#session-target-选择" aria-label="Permalink to &quot;Session Target 选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>适用场景</th></tr></thead><tbody><tr><td><code>isolated</code>（推荐）</td><td>独立 session，完全隔离</td><td>Cron 任务、后台处理</td></tr><tr><td><code>main</code></td><td>在主 session 中执行</td><td>需要共享上下文</td></tr><tr><td><code>current</code></td><td>在当前 session 执行</td><td>与当前对话协作</td></tr></tbody></table><h3 id="公告投递与-telegram-群组限制" tabindex="-1">公告投递与 Telegram 群组限制 <a class="header-anchor" href="#公告投递与-telegram-群组限制" aria-label="Permalink to &quot;公告投递与 Telegram 群组限制&quot;">​</a></h3><p><strong>问题</strong>：在 Telegram 群组中触发 Subagent，任务完成后主 Agent 的公告会被静默丢弃，Gateway 日志显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Outbound not configured for channel: telegram</span></span></code></pre></div><p><strong>根因</strong>：Subagent completion announce 路径未配置 outbound。</p><p><strong>临时解决方案</strong>：</p><ol><li>改用 <strong>DM（私人对话）</strong> 触发 Subagent</li><li>监控 Gateway 日志：<code>openclaw gateway logs | grep subagent</code></li><li>关注官方修复：<a href="https://github.com/openclaw/openclaw/issues/56032" target="_blank" rel="noreferrer">Issue #56032</a></li></ol><hr><h2 id="_7-1-7-⚠️-v2026-3-24-已知-bug-汇总" tabindex="-1">7.1.7 ⚠️ v2026.3.24 已知 Bug 汇总 <a class="header-anchor" href="#_7-1-7-⚠️-v2026-3-24-已知-bug-汇总" aria-label="Permalink to &quot;7.1.7 ⚠️ v2026.3.24 已知 Bug 汇总&quot;">​</a></h2><h3 id="影响多-agent-协作的活跃-bug" tabindex="-1">影响多 Agent 协作的活跃 Bug <a class="header-anchor" href="#影响多-agent-协作的活跃-bug" aria-label="Permalink to &quot;影响多 Agent 协作的活跃 Bug&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Bug</th><th>严重度</th><th>问题</th><th>Workaround</th></tr></thead><tbody><tr><td><a href="https://github.com/openclaw/openclaw/issues/56044" target="_blank" rel="noreferrer">#56044</a></td><td>高</td><td><code>/stop</code> 无法中断任务</td><td><code>messages.queue.mode: &quot;steer&quot;</code></td></tr><tr><td><a href="https://github.com/openclaw/openclaw/issues/56032" target="_blank" rel="noreferrer">#56032</a></td><td>高</td><td>Telegram 群组 Subagent 公告失败</td><td>改用 DM 触发</td></tr><tr><td><a href="https://github.com/openclaw/openclaw/issues/56045" target="_blank" rel="noreferrer">#56045</a></td><td>中</td><td>Cron 删除后持续投递</td><td>删除后重启 Gateway</td></tr><tr><td><a href="https://github.com/openclaw/openclaw/issues/56049" target="_blank" rel="noreferrer">#56049</a></td><td>中</td><td>Heartbeat 风暴</td><td>监控日志，必要时重启</td></tr><tr><td><a href="https://github.com/openclaw/openclaw/issues/55380" target="_blank" rel="noreferrer">#55380</a></td><td>紧急</td><td>timeoutSeconds 未生效</td><td>手动 kill 失控 agent</td></tr><tr><td><a href="https://github.com/openclaw/openclaw/issues/55385" target="_blank" rel="noreferrer">#55385</a></td><td>紧急</td><td>memory_search 被禁用</td><td>等待官方修复</td></tr></tbody></table><hr><h2 id="_7-1-8-多-agent-最佳实践" tabindex="-1">7.1.8 多 Agent 最佳实践 <a class="header-anchor" href="#_7-1-8-多-agent-最佳实践" aria-label="Permalink to &quot;7.1.8 多 Agent 最佳实践&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ 推荐做法：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 始终配置 messages.queue.mode: &quot;steer&quot;</span></span>
<span class="line"><span>   → 保持对运行任务的控制能力</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Subagent 用 isolated session</span></span>
<span class="line"><span>   → 隔离环境避免干扰主会话</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 设置合理的 runTimeoutSeconds</span></span>
<span class="line"><span>   → 防止失控 agent 无限占用资源</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Cron 任务配合 skipWhenIdle</span></span>
<span class="line"><span>   → 减少空闲时不必要的执行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. Telegram 群组场景用 DM 中转</span></span>
<span class="line"><span>   → 绕过公告投递限制</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 避免做法：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 在高 heartbeat 频率时触发 Subagent</span></span>
<span class="line"><span>   → 可能触发 #56049 Heartbeat 风暴</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 大量 Subagent 并行启动</span></span>
<span class="line"><span>   → 资源竞争，建议控制在 3-5 个以内</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 跨群组共享同一 Agent</span></span>
<span class="line"><span>   → 上下文混淆，建议独立配置</span></span></code></pre></div><hr><h2 id="_7-1-9-常见问题" tabindex="-1">7.1.9 常见问题 <a class="header-anchor" href="#_7-1-9-常见问题" aria-label="Permalink to &quot;7.1.9 常见问题&quot;">​</a></h2><h3 id="q1-agent-之间如何通信" tabindex="-1">Q1: Agent 之间如何通信 <a class="header-anchor" href="#q1-agent-之间如何通信" aria-label="Permalink to &quot;Q1: Agent 之间如何通信&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解决：</span></span>
<span class="line"><span>1. 共享上下文（通过 workspace 文件）</span></span>
<span class="line"><span>2. 结构化消息（JSON 格式）</span></span>
<span class="line"><span>3. 约定协议（通过 session send）</span></span></code></pre></div><h3 id="q2-subagent-公告没有出现在群组里" tabindex="-1">Q2: Subagent 公告没有出现在群组里 <a class="header-anchor" href="#q2-subagent-公告没有出现在群组里" aria-label="Permalink to &quot;Q2: Subagent 公告没有出现在群组里&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原因：Telegram 群组公告路径未配置 outbound（#56032）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解决：</span></span>
<span class="line"><span>1. 改用 DM 触发 Subagent</span></span>
<span class="line"><span>2. 通过 /sessions history 查看执行结果</span></span>
<span class="line"><span>3. 监控日志排查</span></span></code></pre></div><h3 id="q3-cron-删除后仍然收到推送" tabindex="-1">Q3: Cron 删除后仍然收到推送 <a class="header-anchor" href="#q3-cron-删除后仍然收到推送" aria-label="Permalink to &quot;Q3: Cron 删除后仍然收到推送&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原因：#56045 Cron 删除后持续投递 bug</span></span>
<span class="line"><span></span></span>
<span class="line"><span>解决：</span></span>
<span class="line"><span>1. cron remove 后执行 openclaw gateway restart</span></span>
<span class="line"><span>2. 确认 job 确实已被删除</span></span>
<span class="line"><span>3. 观察是否停止</span></span></code></pre></div><hr><h2 id="本节小结" tabindex="-1">本节小结 <a class="header-anchor" href="#本节小结" aria-label="Permalink to &quot;本节小结&quot;">​</a></h2><ol><li><strong>多 Agent</strong>：专业分工，协作完成复杂任务</li><li><strong>架构</strong>：Dispatcher + Agent + Aggregator</li><li><strong>角色</strong>：协调者、执行者、审查者、规划者</li><li><strong>模式</strong>：串行、并行、分支、循环</li></ol><hr><h2 id="课后思考" tabindex="-1">课后思考 <a class="header-anchor" href="#课后思考" aria-label="Permalink to &quot;课后思考&quot;">​</a></h2><ol><li>什么场景适合用多 Agent？</li><li>如何设计 Agent 之间的通信？</li><li>如何平衡效率和成本？</li></ol>`,64)])])}const u=n(l,[["render",t]]);export{g as __pageData,u as default};
